                    if enemy:GetUnitName() == "npc_dota_hero_lina" or enemy:GetUnitName() == "npc_dota_hero_lion" then
                        -- Прожимаем Лотус перед тем как подойти ближе, чтобы отразить спелл!
                        bot:Action_UseAbilityOnEntity(lotus_item, bot)
